- "fishing zones" refers to 'strata';
- "ventured into" implies conducting trips;
- "the most" means the maximum number of trips for each captain-stratum combination;
- "highest frequency of visits to any zone" means the maximum number of trips to any stratum for each captain.

sql:
SELECT species, SUM(weight) AS total_catch_weight
FROM catch_records
GROUP BY species;

SELECT trip_id, COUNT(DISTINCT species) AS number_of_species_caught
FROM catch_records
GROUP BY trip_id;

